import hashlib
import modal
from fastapi import FastAPI, Request

app = modal.App("event-driven-pipeline")

queue = modal.Queue.from_name("pipeline-events", create_if_missing=True)
registry = modal.Dict.from_name("pipeline-registry", create_if_missing=True)
volume = modal.Volume.from_name("pipeline-artifacts", create_if_missing=True)

image = modal.Image.debian_slim().pip_install("fastapi", "uvicorn")

web_app = FastAPI()

@web_app.post("/submit")
async def submit(request: Request):
    body = await request.json()
    data = body.get("data", "")

    # Enqueue the submission
    queue.put(data)

    # Update registry
    current_submitted = registry.get("total_submitted", 0)
    registry["total_submitted"] = current_submitted + 1

    return {"status": "success", "message": "Data submitted"}

@web_app.get("/status")
def status():
    return {
        "total_submitted": registry.get("total_submitted", 0),
        "total_processed": registry.get("total_processed", 0)
    }

@app.function(image=image)
@modal.asgi_app()
def api():
    return web_app

@app.function(volumes={"/data": volume}, retries=2)
def worker(item: str):
    # Compute deterministic hash
    hash_val = hashlib.sha256(item.encode()).hexdigest()

    # Write to volume
    file_path = f"/data/{hash_val}.txt"
    with open(file_path, "w") as f:
        f.write(item)

    # Commit volume
    volume.commit()

@app.local_entrypoint()
def main():
    items = ["item1", "item2", "item3"]

    for item in items:
        queue.put(item)

    for _ in range(3):
        item = queue.get()
        worker.remote(item)

    current_processed = registry.get("total_processed", 0)
    registry["total_processed"] = current_processed + 3
    print("Pipeline run complete.")
